#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    for(int i=0;i<T;++i){
        double r; scanf("%lf",&r);
        double area = 3.14 * r * r;
        printf("%g\n", area);
    }
    return 0;
}

